Gender Gap Query in R

sparql_query = '
SELECT ?genderLabel ?count
WHERE {
  {
    SELECT ?gender (COUNT(?person) AS ?count) WHERE {
      ?person wdt:P31 wd:Q5 .
      ?person wdt:P27 wd:Q183 .
      ?person wdt:P21 ?gender .
    }
    GROUP BY ?gender
  }
  SERVICE wikibase:label { bd:serviceParam wikibase:language "de,en". }
}
ORDER BY DESC(?count)
'

Abgeordnete Query in R

sparql_query_abg = '
SELECT DISTINCT ?person ?personLabel ?gender ?article WHERE {
  ?person p:P39 ?positionStatement .

  ?positionStatement ps:P39 wd:Q1939555 .   # Mitglied des Deutschen Bundestages

  ?positionStatement pq:P2937 wd:Q124661964 . # 21. Deutscher Bundestag (Q-ID einsetzen)

  ?person wdt:P21 ?gender.

  ?article schema:about ?person;
           schema:isPartOf &lt;https://de.wikipedia.org/&gt;.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "de,en". }
}
ORDER BY ?personLabel
'

